 617→    private void moderateComment(
 618→            @NonNull ReaderActivityCommentListBinding binding,
 619→            @NonNull ReaderIncludeCommentBoxBinding boxBinding,
 620→            ReaderComment comment,
 621→            CommentStatus newStatus,
 622→            int undoMessage,
 623→            Stat tracker
