 626→        checkEmptyView(binding, boxBinding);
 627→
 628→        Snackbar snackbar = WPSnackbar.make(
 629→                binding.coordinatorLayout, undoMessage, Snackbar.LENGTH_LONG
 630→        ).setAction(R.string.undo, view -> getCommentAdapter(binding, boxBinding).refreshComments());
 631→
 632→        snackbar.addCallback(new BaseCallback<Snackbar>() {
 633→            @Override
 634→            public void onDismissed(@Nullable Snackbar transientBottomBar, int event) {
 635→                super.onDismissed(transientBottomBar, event);
 636→
 637→                if (event == DISMISS_EVENT_ACTION) {
 638→                    AnalyticsUtils.trackCommentActionWithReaderPostDetails(
 639→                            Stat.COMMENT_MODERATION_UNDO,
 640→                            AnalyticsCommentActionSource.READER, mPost
 641→                    );
 642→                    return;
 643→                }
 644→
 645→                AnalyticsUtils.trackCommentActionWithReaderPostDetails(
 646→                        tracker,
 647→                        AnalyticsCommentActionSource.READER,
 648→                        mPost
 649→                );
 650→                ReaderCommentActions.moderateComment(comment, newStatus);
 651→            }
 652→        });
 653→
 654→        snackbar.show();
